export type IconName = keyof typeof Icons

interface IconProps extends React.SVGProps<SVGSVGElement> {
  name?: IconName
  icon?: LucideIcon | React.ComponentType<any>
  size?: number | string
}

/**
 * Universal Icon component that supports both the internal custom icon library
 * and external icon libraries like Lucide.
 */
const Icon = React.forwardRef<SVGSVGElement, IconProps>(
  ({ name, icon: IconComponent, size = 24, className, ...props }, ref) => {
    // 1. Check if name exists in custom icon library
    if (name && Icons[name]) {
      const CustomIcon = Icons[name]
      return (
        <CustomIcon
          ref={ref as any}
          width={size}
          height={size}
          className={cn("shrink-0", className)}
          {...props}
        />
      )
    }

    // 2. Check if a component was passed (e.g. from Lucide)
    if (IconComponent) {
      return (
        <IconComponent
          ref={ref}
          size={size}
          className={cn("shrink-0", className)}
          {...props}
        />
      )
    }

    // 3. Fallback to rendering children within an SVG wrapper if provided
    if (props.children) {
      return (
        <svg
          ref={ref}
          width={size}
          height={size}
          viewBox={props.viewBox || "0 0 24 24"}
          fill="none"
          xmlns="http://www.w3.org/2000/svg"
          className={cn("shrink-0", className)}
          {...props}
        >
          {props.children}
        </svg>
      )
    }

    return null
  }
)

Icon.displayName = "Icon"

export { Icon }
